class Solution:
    def minRectanglesToCoverPoints(self, points, w: int) -> int:
        xs = sorted(set(p[0] for p in points))
        count = 0
        i = 0
        while i < len(xs):
            start = xs[i]
            count += 1
            while i < len(xs) and xs[i] <= start + w:
                i += 1
        return count

