solutions.javascript:
var minRectanglesToCoverPoints = function(points, w) {
    const xs = [...new Set(points.map(p => p[0]))].sort((a, b) => a - b);
    let count = 0, i = 0;
    while (i < xs.length) {
        const start = xs[i];
        count++;
        while (i < xs.length && xs[i] <= start + w) i++;
    }
    return count;
};
